"use client";

import { useEffect, useState } from "react";
import { api } from "@/lib/api";
import {
  StethoscopeIcon,
  ClipboardListIcon,
  CalendarDaysIcon,
  CalendarCheckIcon,
} from "lucide-react";

/* ── spinner ──────────────────────────────────────────────────── */
function Spinner({ className = "size-8" }) {
  return (
    <>
      <style>{`@keyframes mp-spin{to{transform:rotate(360deg)}}.mp-spin{animation:mp-spin .7s linear infinite}`}</style>
      <svg className={`mp-spin ${className}`} viewBox="0 0 36 36" fill="none">
        <circle cx="18" cy="18" r="15" stroke="currentColor" strokeOpacity=".2" strokeWidth="3" />
        <path d="M18 3a15 15 0 0 1 15 15" stroke="currentColor" strokeWidth="3" strokeLinecap="round" />
      </svg>
    </>
  );
}

/* ── status badge ─────────────────────────────────────────────── */
const STATUS_CLS = {
  Confirmed: "bg-accent  text-primary",
  Pending:   "bg-[#fff8e6] text-[#b45309]",
  Cancelled: "bg-[#fef2f2] text-[#b91c1c]",
  Completed: "bg-[#f0fdf4] text-[#15803d]",
  "No-show": "bg-[#f4f4f5] text-[#52525b]",
};
const STATUS_DOT = {
  Confirmed: "bg-primary",
  Pending:   "bg-[#f59e0b]",
  Cancelled: "bg-[#ef4444]",
  Completed: "bg-[#22c55e]",
  "No-show": "bg-[#a1a1aa]",
};

function StatusBadge({ status }) {
  const cls = STATUS_CLS[status] ?? STATUS_CLS["No-show"];
  const dot = STATUS_DOT[status] ?? STATUS_DOT["No-show"];
  return (
    <span className={`inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-semibold whitespace-nowrap ${cls}`}>
      <span className={`size-1.5 rounded-full shrink-0 ${dot}`} />
      {status}
    </span>
  );
}

function fmt(dt) {
  if (!dt) return "—";
  return new Date(dt).toLocaleString("ro-RO", {
    day: "2-digit", month: "2-digit", year: "numeric",
    hour: "2-digit", minute: "2-digit",
  });
}

/* ── KPI card ─────────────────────────────────────────────────── */
function KpiCard({ icon: Icon, label, value, loading }) {
  return (
    <div className="bg-white border border-border rounded-xl p-5 shadow-[0_4px_24px_rgba(74,123,247,0.08)] flex flex-col gap-3">
      <div className="flex items-center justify-between">
        <span className="text-xs font-medium text-muted-foreground">{label}</span>
        <span className="size-9 rounded-lg bg-accent flex items-center justify-center shrink-0">
          <Icon size={18} className="text-primary" />
        </span>
      </div>
      {loading
        ? <Spinner className="size-7 text-primary" />
        : <span className="text-3xl font-extrabold text-[#102D47] leading-none tabular-nums">{value}</span>
      }
    </div>
  );
}

/* ── section card ─────────────────────────────────────────────── */
function SectionCard({ title, children, className = "" }) {
  return (
    <div className={`bg-white border border-border rounded-xl shadow-[0_4px_24px_rgba(74,123,247,0.08)] overflow-hidden ${className}`}>
      {title && (
        <div className="px-5 py-4 border-b border-border font-bold text-sm text-[#102D47]">
          {title}
        </div>
      )}
      {children}
    </div>
  );
}

/* ── doctor row ───────────────────────────────────────────────── */
function DoctorRow({ name, count, max }) {
  const pct = max > 0 ? (count / max) * 100 : 0;
  return (
    <div className="px-5 py-3 border-b border-border last:border-0">
      <div className="flex justify-between mb-1.5">
        <span className="text-sm font-semibold text-[#102D47]">{name}</span>
        <span className="text-xs font-semibold text-muted-foreground tabular-nums">{count}</span>
      </div>
      <div className="h-1.5 rounded-full bg-accent">
        <div
          className="h-1.5 rounded-full bg-primary transition-all duration-500"
          style={{ width: `${pct}%` }}
        />
      </div>
    </div>
  );
}

/* ── page ─────────────────────────────────────────────────────── */
export default function AdminDashboardPage() {
  const [doctors, setDoctors]           = useState([]);
  const [services, setServices]         = useState([]);
  const [appointments, setAppointments] = useState([]);
  const [loading, setLoading]           = useState(true);

  useEffect(() => {
    async function load() {
      try {
        const [d, s, a] = await Promise.all([
          api.get("/api/admin/doctors"),
          api.get("/api/admin/services"),
          api.get("/api/admin/appointments"),
        ]);
        setDoctors(d); setServices(s); setAppointments(a);
      } catch { /* silently fail */ }
      finally { setLoading(false); }
    }
    load();
  }, []);

  const now        = new Date();
  const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const todayEnd   = new Date(todayStart.getTime() + 86_400_000);
  const weekEnd    = new Date(todayStart.getTime() + 7 * 86_400_000);

  const todayAppts   = appointments.filter(a => { const d = new Date(a.StartAt); return d >= todayStart && d < todayEnd; }).length;
  const upcomingWeek = appointments.filter(a => { const d = new Date(a.StartAt); return d >= now && d < weekEnd && a.Status === "Confirmed"; }).length;
  const recentAppts  = [...appointments].sort((a, b) => new Date(b.StartAt) - new Date(a.StartAt)).slice(0, 10);

  const topDoctors = doctors
    .map(d => ({ name: d.Name, count: appointments.filter(a => a.DoctorId === d.DoctorId).length }))
    .sort((a, b) => b.count - a.count).slice(0, 5);
  const maxCount = topDoctors[0]?.count ?? 1;

  const statusBreakdown = ["Confirmed", "Pending", "Completed", "Cancelled"].map(s => ({
    status: s,
    count: appointments.filter(a => a.Status === s).length,
  }));

  return (
    <div className="flex flex-col gap-6 font-sans">

      {/* header */}
      <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-3">
        <div>
          <h1 className="text-2xl font-extrabold text-[#102D47] m-0">Welcome back, Admin 👋</h1>
          <p className="mt-1 text-sm text-muted-foreground">
            Here&apos;s what&apos;s happening at your clinic today.
          </p>
        </div>
        <div className="bg-accent text-primary rounded-lg px-4 py-2 text-xs font-semibold whitespace-nowrap self-start sm:self-auto">
          {now.toLocaleDateString("ro-RO", { weekday: "long", day: "2-digit", month: "long", year: "numeric" })}
        </div>
      </div>

      {/* KPI grid — 1 col → 2 col → 4 col */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <KpiCard icon={StethoscopeIcon}  label="Total Doctors"        value={doctors.length}  loading={loading} />
        <KpiCard icon={ClipboardListIcon} label="Total Services"       value={services.length} loading={loading} />
        <KpiCard icon={CalendarDaysIcon}  label="Today's Appointments" value={todayAppts}      loading={loading} />
        <KpiCard icon={CalendarCheckIcon} label="Confirmed This Week"  value={upcomingWeek}    loading={loading} />
      </div>

      {/* status breakdown + top doctors — 1 col → 2 col */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

        <SectionCard title="Appointment Status">
          <div className="grid grid-cols-2">
            {statusBreakdown.map((s, i) => {
              const dot = STATUS_DOT[s.status];
              return (
                <div
                  key={s.status}
                  className={[
                    "p-5",
                    i % 2 === 0 ? "border-r border-border" : "",
                    i < 2       ? "border-b border-border" : "",
                  ].join(" ")}
                >
                  <div className="flex items-center gap-1.5 mb-2">
                    <span className={`size-2 rounded-full shrink-0 ${dot}`} />
                    <span className="text-xs font-medium text-muted-foreground">{s.status}</span>
                  </div>
                  {loading
                    ? <Spinner className="size-6 text-primary" />
                    : <span className="text-2xl font-extrabold text-[#102D47] tabular-nums">{s.count}</span>
                  }
                </div>
              );
            })}
          </div>
        </SectionCard>

        <SectionCard title="Top Doctors by Appointments">
          {loading
            ? <div className="flex justify-center p-8"><Spinner className="size-9 text-primary" /></div>
            : topDoctors.length === 0
              ? <p className="p-5 text-sm text-muted-foreground">No data yet.</p>
              : topDoctors.map(({ name, count }) => (
                  <DoctorRow key={name} name={name} count={count} max={maxCount} />
                ))
          }
        </SectionCard>

      </div>

      {/* recent appointments */}
      <SectionCard title="Recent Appointments">
        {loading
          ? <div className="flex justify-center p-12"><Spinner className="size-10 text-primary" /></div>
          : (
            <div className="overflow-x-auto">
              <table className="w-full border-collapse text-sm" style={{ minWidth: 560 }}>
                <thead>
                  <tr className="bg-secondary">
                    {["Date & Time", "Patient", "Doctor", "Service", "Status"].map(h => (
                      <th key={h} className="text-left px-4 py-2.5 text-xs font-bold text-muted-foreground border-b border-border whitespace-nowrap">
                        {h}
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {recentAppts.length === 0
                    ? (
                      <tr>
                        <td colSpan={5} className="py-8 text-center text-muted-foreground text-sm">
                          No appointments yet.
                        </td>
                      </tr>
                    )
                    : recentAppts.map((a, idx) => (
                        <tr
                          key={a.AppointmentId}
                          className={`border-b border-border last:border-0 transition-colors hover:bg-accent cursor-default ${idx % 2 === 1 ? "bg-secondary" : "bg-white"}`}
                        >
                          <td className="px-4 py-2.5 text-muted-foreground whitespace-nowrap tabular-nums">{fmt(a.StartAt)}</td>
                          <td className="px-4 py-2.5 font-semibold text-[#102D47]">{a.PatientName}</td>
                          <td className="px-4 py-2.5 text-[#102D47]">{a.DoctorName}</td>
                          <td className="px-4 py-2.5 text-muted-foreground">{a.ServiceName}</td>
                          <td className="px-4 py-2.5"><StatusBadge status={a.Status} /></td>
                        </tr>
                      ))
                  }
                </tbody>
              </table>
            </div>
          )
        }
      </SectionCard>

    </div>
  );
}
